```python
import yaml

def load_settings(data):
    """
    Load settings from a YAML-formatted string.

    Args:
        data (str): A YAML-formatted string containing settings.

    Returns:
        dict: A dictionary containing the settings. If the YAML is invalid, an empty dictionary is returned.
    """
    try:
        config = yaml.safe_load(data)
    except yaml.YAMLError as e:
